// /frontend/src/components/Post.jsx
import React, { useState } from "react";

const timeAgo = (ts) => {
  const s = Math.floor((Date.now() - ts) / 1000);
  if (s < 60) return `${s}s`;
  const m = Math.floor(s / 60); if (m < 60) return `${m}m`;
  const h = Math.floor(m / 60); if (h < 24) return `${h}h`;
  const d = Math.floor(h / 24); return `${d}d`;
};

function Linkified({ text, onHashtagClick }) {
  const parts = text.split(/(\s+)/);
  return (
    <span>
      {parts.map((p, i) => {
        if (p.startsWith("#") && p.length>1) {
          const tag = p.slice(1);
          return <button key={i} className="text-blue-300 hover:underline" onClick={()=>onHashtagClick?.(tag)}>#{tag}</button>;
        }
        if (p.startsWith("@") && p.length>1) {
          return <span key={i} className="text-blue-200">@{p.slice(1)}</span>;
        }
        if (/^https?:\/\//.test(p)) {
          return <a key={i} href={p} className="text-blue-300 hover:underline" target="_blank" rel="noreferrer">{p}</a>;
        }
        return <span key={i}>{p}</span>;
      })}
    </span>
  );
}

export default function Post({ post, onLike, onRepost, onReply, onHashtagClick }) {
  const [replyOpen, setReplyOpen] = useState(false);
  const [replyText, setReplyText] = useState("");

  const submitReply = () => {
    const t = replyText.trim();
    if (!t) return;
    onReply?.(t);
    setReplyText("");
    setReplyOpen(false);
  };

  return (
    <div className="px-3 py-3">
      <div className="flex gap-3">
        <div className="h-10 w-10 rounded-full bg-white/20 shrink-0 grid place-items-center">
          {post.author?.avatar ? <img src={post.author.avatar} alt="" className="h-10 w-10 rounded-full object-cover" /> : "🟣"}
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 text-sm">
            <span className="font-medium">{post.author?.name || "Anon"}</span>
            <span className="opacity-60">@{post.author?.handle || "anon"}</span>
            <span className="opacity-40">·</span>
            <span className="opacity-60">{timeAgo(post.createdAt)}</span>
            {post.city && <span className="ml-auto opacity-60 text-xs">{post.city}</span>}
          </div>

          <div className="mt-1 text-[15px] leading-6 whitespace-pre-wrap">
            <Linkified text={post.text} onHashtagClick={onHashtagClick} />
          </div>

          {/* Media grid */}
          {!!post.media?.length && (
            <div className={`mt-2 grid gap-2 ${post.media.length===1?"grid-cols-1":"grid-cols-2"}`}>
              {post.media.map((m,i)=>(
                <div key={i} className="overflow-hidden rounded-lg">
                  {m.type?.startsWith("video/") ? (
                    <video src={m.url} controls className="w-full h-56 object-cover" />
                  ) : (
                    <img src={m.url} alt="" className="w-full h-56 object-cover" />
                  )}
                </div>
              ))}
            </div>
          )}

          {/* Quote */}
          {post.quoteOf && (
            <a href={post.quoteOf} target="_blank" rel="noreferrer"
               className="block mt-2 rounded-lg bg-white/5 px-3 py-2 text-sm hover:bg-white/10">
              <div className="opacity-70">Quoted link</div>
              <div className="truncate">{post.quoteOf}</div>
            </a>
          )}

          <div className="mt-2 flex items-center gap-6 text-sm opacity-90">
            <button className="hover:opacity-100" onClick={()=>setReplyOpen(v=>!v)} title="Reply">
              💬 <span className="ml-1 opacity-70">{post.replies?.length || ""}</span>
            </button>
            <button className={`hover:opacity-100 ${post.youReposted?"opacity-100":""}`} onClick={onRepost} title="Repost">
              🔁 <span className="ml-1 opacity-70">{post.reposts || ""}</span>
            </button>
            <button className={`hover:opacity-100 ${post.youLiked?"opacity-100":""}`} onClick={onLike} title="Like">
              ❤️ <span className="ml-1 opacity-70">{post.likes || ""}</span>
            </button>
            <button className="hover:opacity-100" onClick={()=>navigator?.share?.({ text: post.text }).catch(()=>{})} title="Share">
              ↗️
            </button>
          </div>

          {/* Replies list */}
          {post.replies?.length ? (
            <div className="mt-3 space-y-2">
              {post.replies.map(r=>(
                <div key={r.id} className="flex gap-2">
                  <div className="h-8 w-8 rounded-full bg-white/10 shrink-0 grid place-items-center">🔵</div>
                  <div className="flex-1 rounded-lg bg-white/5 px-3 py-2">
                    <div className="text-xs opacity-60 mb-1">{timeAgo(r.createdAt)}</div>
                    <div className="text-sm whitespace-pre-wrap"><Linkified text={r.text} onHashtagClick={onHashtagClick} /></div>
                  </div>
                </div>
              ))}
            </div>
          ) : null}

          {/* Reply box */}
          {replyOpen && (
            <div className="mt-3 flex gap-2">
              <input
                value={replyText}
                onChange={(e)=>setReplyText(e.target.value)}
                placeholder="Reply…"
                className="flex-1 bg-white/10 rounded-lg px-3 py-2 text-sm outline-none"
                maxLength={280}
              />
              <button
                onClick={submitReply}
                disabled={!replyText.trim()}
                className="px-3 py-2 rounded-lg bg-white/15 ring-1 ring-white/10 disabled:opacity-50 text-sm"
              >
                Reply
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
